#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
int n, m, tot, ans;
CI maxn = 1e5 + 5;
struct node
{
	int a, b, l;
} c[maxn];
bool cmp(const node &aa, const node &bb)
{
	return aa.l < bb.l;
}
int fa[maxn];
int find(int x)
{
	if (fa[x] == x) return x;
	return fa[x] = find(fa[x]);
}
void k()
{
	for (int i = 1; i <= m; ++i)
	{
		int u = find(c[i].a);
		int v = find(c[i].b);
		if (u == v) continue;
		fa[u] = v;
		tot++;
		ans = c[i].l;
		if (tot == n - 1) break;
	}
}
int main(void)
{
	cin >> n >> m;
	for (int i = 1; i <= m; ++i)
	{
		cin >> c[i].a >> c[i].b >> c[i].l;
	}
	for (int i = 1; i <= n; ++i)
	{
		fa[i] = i;
	}
	sort(c + 1, c + 1 + m, cmp);
	k();
	cout << ans;
	return false;
}
